                    </p>
                    <Link to="/products" className="primary-btn">
                        <ShoppingBag size={18} />
                        Start Shopping
                        <ArrowRight size={18} />
                    </Link>
                </div>
            ) : (
                <div className="favorites-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '16px' }}>
                    {/* Render favorites if they exist */}
                    {favorites.map(item => (
                        <div key={item.id} className="favorite-card">
                            {/* Card content */}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Favorites;

import { useState, useEffect } from 'react';
import { Bell, Truck, Tag, CreditCard, Inbox } from 'lucide-react';
import { userAPI } from '../../services/api';

const Notifications = () => {
    // Professional empty state - no mocked data
    const [notifications, setNotifications] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchNotifications = async () => {
            try {
                const res = await userAPI.getNotifications();
                if (res.success) {
                    setNotifications(res.data);
                }
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        fetchNotifications();
    }, []);

    return (
        <div className="profile-section fade-in">
            <h2 className="section-title">Notifications</h2>

            {notifications.length === 0 ? (
                <div className="profile-empty-state">
                    <div className="empty-icon-container" style={{ background: '#f5f5f5', color: '#bdbdbd' }}>
                        <Inbox size={32} />
                    </div>
                    <h3 className="empty-title">All caught up!</h3>
                    <p className="empty-desc">
                        You have no new notifications. Activity on your orders and offers will show up here.
                    </p>
                </div>
            ) : (
                <div className="notifications-list">
                    {notifications.map(notification => (
                        <div
                            key={notification.id}
                            className={`notification-item ${notification.read ? 'read' : ''}`}
                        >
                            <div className="notif-icon" style={{
                                background: notification.type === 'Order' ? '#e3f2fd' :
                                    notification.type === 'Offer' ? '#fff3e0' :
                                        notification.type === 'Wallet' ? '#e8f5e9' : '#f5f5f5',
                                color: notification.type === 'Order' ? '#1976d2' :
                                    notification.type === 'Offer' ? '#ff9800' :
                                        notification.type === 'Wallet' ? '#2e7d32' : '#757575'
                            }}>
                                {notification.type === 'Order' && <Truck size={18} />}
                                {notification.type === 'Offer' && <Tag size={18} />}
                                {notification.type === 'Wallet' && <CreditCard size={18} />}
                                {notification.type === 'System' && <Bell size={18} />}
                            </div>
                            <div className="notif-content">
                                <div className="notif-header">
                                    <h4 className="notif-title">{notification.title}</h4>
                                    <span className="notif-date">{notification.date}</span>
                                </div>
                                <p className="notif-desc">{notification.desc}</p>
                            </div>
                        </div>
                    ))}

                    <button
                        className="btn-text"
                        style={{ width: '100%', textAlign: 'center', marginTop: '16px', display: 'block' }}
                        onClick={() => setNotifications(notifications.map(n => ({ ...n, read: true })))}
                    >
                        Mark all as read
                    </button>

                </div>
            )}
        </div>
    );
};

export default Notifications;

import { useState, useEffect } from 'react';
import { Tag, Copy, Check, TicketPercent } from 'lucide-react';
import toast from 'react-hot-toast';
import { publicAPI } from '../../services/api';

const Offers = () => {
    // Professional empty state - no mocked data
    const [offers, setOffers] = useState([]);
    const [copied, setCopied] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchOffers = async () => {
            try {
                const res = await publicAPI.getOffers();
                if (res.success) {
                    setOffers(res.data.offers);
                }
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        fetchOffers();
    }, []);

    const copyCode = (code) => {
        navigator.clipboard.writeText(code);
        setCopied(code);
        toast.success(`Coupon code ${code} copied!`);
        setTimeout(() => setCopied(null), 2000);
    };

    return (
        <div className="profile-section fade-in">
            <h2 className="section-title">Exclusive Offers & Coupons</h2>

            {offers.length === 0 ? (
                <div className="profile-empty-state">
                    <div className="empty-icon-container" style={{ background: '#fff3e0', color: '#ff9800' }}>
                        <TicketPercent size={32} />
                    </div>
                    <h3 className="empty-title">No Active Offers</h3>
                    <p className="empty-desc">
                        There are no active coupons or offers available at the moment. Please check back later for exciting deals!
                    </p>
                </div>
            ) : (
                <div className="offers-grid">
                    {offers.map(offer => (
                        <div key={offer.id} className="offer-card-item">
                            <div className="offer-tag">
                                {offer.discount}
                            </div>
                            <div className="offer-header">
                                <div className="offer-icon">
                                    <Tag size={24} />
                                </div>
                                <div>
                                    <h3 className="offer-code">{offer.code}</h3>
                                    <p className="offer-exp">{offer.exp}</p>
                                </div>
                            </div>
                            <p className="offer-desc">{offer.desc}</p>
                            <button
                                onClick={() => copyCode(offer.code)}
                                className={`copy-btn ${copied === offer.code ? 'copied' : ''}`}
                            >
                                {copied === offer.code ? <Check size={18} /> : <Copy size={18} />}
                                {copied === offer.code ? 'Copied!' : 'Copy Code'}
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Offers;

import { useState, useEffect } from 'react';
import { Wallet, ArrowRight, History } from 'lucide-react';
import { userAPI } from '../../services/api';

const WalletPage = () => {
    // Professional empty state - no mocked data
    const [balance, setBalance] = useState(0);
    const [history, setHistory] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchWallet = async () => {
            try {
                const res = await userAPI.getWallet();
                if (res.success) {
                    setBalance(res.data.balance);
                    setHistory(res.data.history);
                }
            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        };
        fetchWallet();
    }, []);

    return (
        <div className="profile-section fade-in">
            <h2 className="section-title">My Wallet</h2>

            {/* Balance Card */}
            <div className="wallet-card-main">
                <div className="wallet-bg-icon">
                    <Wallet size={120} />
                </div>
                <div style={{ position: 'relative', zIndex: 10 }}>
                    <p className="wallet-balance-label">Available Balance</p>
                    <h1 className="wallet-balance-amount">Γé╣{balance.toFixed(2)}</h1>
                    <button className="wallet-add-btn">
                        + Add Money
                    </button>
                </div>
            </div>

            {/* History */}
            <h3 className="section-title" style={{ fontSize: '18px', marginTop: '32px' }}>Transaction History</h3>

            {history.length === 0 ? (
                <div className="profile-empty-state" style={{ minHeight: '200px', padding: '32px' }}>
                    <div className="empty-icon-container" style={{ background: '#f5f5f5', color: '#bdbdbd' }}>
                        <History size={24} />
                    </div>
                    <h4 className="empty-title" style={{ fontSize: '16px' }}>No transactions yet</h4>
                    <p className="empty-desc" style={{ marginBottom: 0 }}>
                        Your recent wallet transactions will appear here.
                    </p>
                </div>
            ) : (
                <div style={{ background: '#fff', borderRadius: '12px', border: '1px solid #eee', overflow: 'hidden' }}>
                    {history.map((tx, i) => (
                        <div key={tx.id} style={{ padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: i !== history.length - 1 ? '1px solid #f0f0f0' : 'none' }}>
                            <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                                <div style={{ width: '40px', height: '40px', borderRadius: '50%', background: tx.type === 'Credit' ? '#e8f5e9' : '#ffebee', color: tx.type === 'Credit' ? '#2e7d32' : '#c62828', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                    <ArrowRight size={18} style={{ transform: tx.type === 'Credit' ? 'rotate(45deg)' : 'rotate(-45deg)' }} />
                                </div>
                                <div>
                                    <p style={{ fontWeight: 600, fontSize: '14px', marginBottom: '2px' }}>{tx.desc}</p>
                                    <p style={{ fontSize: '12px', color: '#888' }}>{tx.date}</p>
                                </div>
                            </div>
                            <span style={{ fontWeight: 700, fontSize: '14px', color: tx.type === 'Credit' ? '#2e7d32' : '#c62828' }}>
                                {tx.type === 'Credit' ? '+' : '-'}Γé╣{tx.amount}
                            </span>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default WalletPage;
